function mergeSorted(a, b) {
  // Two pointers i and j into a and b.
  // At each step, push the smaller of a[i] and b[j] to the output.
  // When one runs out, append the rest of the other.
}

solution:
// O(n + m) time, O(n + m) space (for the output).
function mergeSorted(a, b) {
  const out = [];
  let i = 0, j = 0;
  while (i < a.length && j < b.length) {
    if (a[i] <= b[j]) out.push(a[i++]);
    else              out.push(b[j++]);
  }
  // Drain whichever side still has items
  while (i < a.length) out.push(a[i++]);
  while (j < b.length) out.push(b[j++]);
  return out;
}
